14615 bool SLPVectorizerPass::runImpl(Function &F, ScalarEvolution *SE_,
14616                                 TargetTransformInfo *TTI_,
14617                                 TargetLibraryInfo *TLI_, AAResults *AA_,
14618                                 LoopInfo *LI_, DominatorTree *DT_,
14619                                 AssumptionCache *AC_, DemandedBits *DB_,
14620                                 OptimizationRemarkEmitter *ORE_) {
14621   if (!RunSLPVectorization)
14622     return false;
14623   SE = SE_;
14624   TTI = TTI_;
14625   TLI = TLI_;
14626   AA = AA_;
14627   LI = LI_;
14628   DT = DT_;
14629   AC = AC_;
14630   DB = DB_;
14631   DL = &F.getParent()->getDataLayout();
14632 
14633   Stores.clear();
14634   GEPs.clear();
