14595 PreservedAnalyses SLPVectorizerPass::run(Function &F, FunctionAnalysisManager &AM) {
14596   auto *SE = &AM.getResult<ScalarEvolutionAnalysis>(F);
14597   auto *TTI = &AM.getResult<TargetIRAnalysis>(F);
14598   auto *TLI = AM.getCachedResult<TargetLibraryAnalysis>(F);
14599   auto *AA = &AM.getResult<AAManager>(F);
14600   auto *LI = &AM.getResult<LoopAnalysis>(F);
14601   auto *DT = &AM.getResult<DominatorTreeAnalysis>(F);
14602   auto *AC = &AM.getResult<AssumptionAnalysis>(F);
14603   auto *DB = &AM.getResult<DemandedBitsAnalysis>(F);
14604   auto *ORE = &AM.getResult<OptimizationRemarkEmitterAnalysis>(F);
14605 
14606   bool Changed = runImpl(F, SE, TTI, TLI, AA, LI, DT, AC, DB, ORE);
14607   if (!Changed)
14608     return PreservedAnalyses::all();
14609 
14610   PreservedAnalyses PA;
14611   PA.preserveSet<CFGAnalyses>();
14612   return PA;
